<section class="auth-shell shell"><div class="auth-card card auth-card-wide"><div class="auth-heading"><span class="maintenance-clock" aria-hidden="true">2</span><p class="eyebrow">Required administrator security</p><h1 class="heading-auth">Set up two-factor authentication</h1><p class="muted">Complete setup before continuing to administrator tools.</p></div><ol class="benefit-list"><li>Open an authenticator app on a trusted device.</li><li>Scan the server-generated QR code or enter the setup key.</li><li>Enter the first six-digit code to confirm.</li><li>Save one-time recovery codes somewhere offline and secure.</li></ol><div class="callout text-center" id="two-factor-key"><strong><?= $esc((string)($data['setup_key_masked']??'Setup key is shown securely by the server')) ?></strong></div><?php if(!empty($data['qr_image_url'])): ?><img src="<?= $esc($data['qr_image_url']) ?>" alt="QR code containing the two-factor setup key" class="u-qr"><?php endif; ?><form class="form-stack" method="post" action="<?= $url('auth.2fa.confirm', [], '/settings/two-factor') ?>"><?= function_exists('csrf_field')?csrf_field():'' ?><label class="field"><span>Six-digit code</span><input name="code" inputmode="numeric" autocomplete="one-time-code" pattern="[0-9]{6}" maxlength="6" required></label><label class="field"><span>Current password</span><input type="password" name="password" autocomplete="current-password" required></label><button class="button button-gold button-wide">Enable two-factor authentication</button></form></div></section>
